const userQuerySchema = z.object({
  limit: z.coerce.number().int().min(1).max(100).default(20),
  offset: z.coerce.number().int().min(0).default(0),
});

app.get('/users', requireAuth, (req, res) => {
  const result = userQuerySchema.safeParse(req.query);
  if (!result.success) {
    return res.status(400).json({ error: 'Invalid query parameters', details: result.error.flatten() });
  }
  const { limit, offset } = result.data;
  // safe to use limit/offset in DB query
  res.json(users.slice(offset, offset + limit));
});
```

